#!/usr/bin/env node
// patch-phase2-jejo.cjs — PHASE 2 : Jejo Studio (Reels TikTok) + durée story 30s.
// Idempotent. Défensif. TSY react-icons.

const fs = require('fs');
const path = require('path');
const ROOT = process.cwd();
let ok = 0, fail = 0;
const good = m => { console.log('  \u2705 ' + m); ok++; };
const skip = m => { console.log('  \u26a0\ufe0f  ' + m); };
const err  = m => { console.log('  \u274c ' + m); fail++; };
const read = rel => { const p = path.join(ROOT, rel); if (!fs.existsSync(p)) return null; return fs.readFileSync(p, 'utf8'); };
const exists = rel => fs.existsSync(path.join(ROOT, rel));
const write = (rel, s) => fs.writeFileSync(path.join(ROOT, rel), s, 'utf8');
function rep(rel, from, to, label) {
  const s = read(rel); if (s == null) { err('Fichier introuvable: ' + rel + ' (' + label + ')'); return; }
  if (s.includes(to)) { good(label + ' (déjà appliqué)'); return; }
  if (!s.includes(from)) { skip('Ancre manquante: ' + label); return; }
  write(rel, s.replace(from, to)); good(label);
}

console.log('\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550');
