// [2] Créer JejoStudio.jsx
console.log('\n[2] src/components/JejoStudio.jsx...');
try {
  const B64 = '';
  fs.writeFileSync(path.join(ROOT, 'src/components/JejoStudio.jsx'), Buffer.from(B64, 'base64').toString('utf8'), 'utf8');
  good('JejoStudio.jsx écrit (' + Math.round(Buffer.from(B64,'base64').length/1024) + ' Ko)');
} catch (e) { err('Écriture JejoStudio.jsx: ' + e.message); }

